function extractSelectedOptionIntent(text, maxOptions) {
  const t = normalizeText(text);

  // Evita confundir horas reales con opciones.
  // Ej: "1:00", "13:00", "1 pm", "1 p.m."
  const looksLikeTime =
    /\b\d{1,2}:\d{2}\b/.test(t) ||
    /\b(am|pm|a\.m\.|p\.m\.)\b/.test(t);

  if (looksLikeTime) {
    return {
      type: "not_option",
      index: null,
      number: null,
    };
  }

  const wordMap = {
    primera: 1,
    primer: 1,
    uno: 1,

    segunda: 2,
    segundo: 2,
    dos: 2,

    tercera: 3,
    tercer: 3,
    tercero: 3,
    tres: 3,

    cuarta: 4,
    cuarto: 4,
    cuatro: 4,

    quinta: 5,
    quinto: 5,
    cinco: 5,

    sexta: 6,
    sexto: 6,
    seis: 6,

    septima: 7,
    septimo: 7,
    siete: 7,

    octava: 8,
    octavo: 8,
    ocho: 8,

    novena: 9,
    noveno: 9,
    nueve: 9,

    decima: 10,
    decimo: 10,
    diez: 10,
  };

  for (const [word, value] of Object.entries(wordMap)) {
    const regex = new RegExp(`\\b${word}\\b`, "i");

    if (regex.test(t)) {
      if (value >= 1 && value <= maxOptions) {
        return {
          type: "valid_option",
          index: value - 1,
          number: value,
        };
      }

      return {
        type: "invalid_option",
        index: null,
        number: value,
      };
    }
  }

  // Casos válidos:
  // "1"
  // "la 1"
  // "opcion 1"
  // "opción 1"
  // "numero 1"
  // "número 1"
  // "alternativa 1"
  const exactNumberMatch = t.match(/^\s*(\d{1,2})\s*$/);

  const optionNumberMatch = t.match(
    /\b(?:la|el|opcion|opción|numero|número|nro|num|alternativa)\s*(\d{1,2})\b/
  );

  const match = exactNumberMatch || optionNumberMatch;

  if (!match) {
    return {
      type: "not_option",
      index: null,
      number: null,
    };
  }

  const selectedNumber = Number(match[1]);

  if (!Number.isInteger(selectedNumber)) {
    return {
      type: "not_option",
      index: null,
      number: null,
    };
  }

  if (selectedNumber < 1 || selectedNumber > maxOptions) {
    return {
      type: "invalid_option",
      index: null,
      number: selectedNumber,
    };
  }

  return {
    type: "valid_option",
    index: selectedNumber - 1,
    number: selectedNumber,
  };
}

