function buildBusinessFaqMessage(topic, ctx) {
  const hasService = !isMissing(ctx.leadState.service_interest);
  const hasVehicle = !isMissing(ctx.leadState.vehicle_type);
  const hasDistrict = !isMissing(ctx.leadState.district);

  const hasFullCommercialContext = hasService && hasVehicle && hasDistrict;

  const closingQuestion = hasFullCommercialContext
    ? "¿Te gustaría que revise el valor o los horarios disponibles?"
    : "Para orientarte mejor, dime qué servicio te interesa, qué tipo de vehículo tienes y en qué comuna sería.";

  const messages = {
    payment_methods:
      `Puedes pagar por transferencia o efectivo. Si prefieres otro medio de pago, lo podemos revisar al momento de coordinar. ${closingQuestion}`,

    home_service:
      `Sí, el servicio es a domicilio. Vamos hasta la dirección que nos indiques y coordinamos el horario según disponibilidad. ${closingQuestion}`,

    requirements:
      `Para realizar el servicio idealmente necesitamos acceso a agua y electricidad cerca del vehículo. Si tienes alguna limitación en el lugar, me la comentas y lo revisamos antes de agendar. ${closingQuestion}`,

    service_duration:
      `La duración depende del servicio y del estado del vehículo, pero normalmente un lavado puede tomar entre 1 y 2 horas aproximadamente. ${closingQuestion}`,

    discounts:
      `Por ahora trabajamos con valores según servicio, tipo de vehículo y comuna. Si son más vehículos o quieres agendar más de un servicio, podemos revisarlo como caso especial. ${closingQuestion}`,

    motorcycle_service:
      `Por ahora el foco principal está en autos, SUV, camionetas y vehículos similares. Si quieres lavar una moto, puedo derivarlo para revisión manual y confirmar si se puede realizar. ¿Quieres que lo revisemos?`,

    basic_vs_premium:
      `El lavado básico está pensado para una mantención general del vehículo. El lavado premium es más completo y se enfoca en una limpieza más detallada interior y exterior. Si el auto necesita una limpieza más profunda, normalmente conviene el premium. ${closingQuestion}`,

    service_includes:
      `El detalle depende del servicio elegido. En general, el lavado básico cubre una limpieza de mantención, mientras que el premium incluye una limpieza más completa interior y exterior. ${closingQuestion}`
  };

  return messages[topic] || null;
}

